INSERT INTO modules (id, title, slug, description, short_summary, provider_name, is_accredited, nqf_level, credits, cost_cents, pricing_model, mode, content_type, duration_hours, difficulty, outcomes, competency_tags, industry_tags, job_role_tags, language, rating, review_count, employer_endorsed, has_remediation, enrollment_count, is_published) VALUES
('00000000-0000-0000-0001-000000000001', 'Digital Literacy Foundations', 'digital-literacy-foundations', 'Build essential digital skills including computer basics, internet navigation, email, cloud tools, and digital safety.', 'Master essential digital skills for the modern workplace', 'CAPACITI', true, '2', 12, 0, 'free', 'online', 'video', 20, 'beginner', ARRAY['Use productivity software','Navigate the internet safely','Manage digital communications','Use cloud storage'], ARRAY['Digital Literacy','Computer Skills','Internet Safety'], ARRAY['Technology','General'], ARRAY['Any Entry Level'], 'English', 4.70, 342, true, true, 2150, true),
('00000000-0000-0000-0001-000000000003', 'Introduction to Programming with Python', 'intro-programming-python', 'Learn programming fundamentals through Python — variables, loops, functions, data structures.', 'Start your coding journey with Python', 'WeThinkCode_', true, '5', 20, 0, 'free', 'online', 'project', 60, 'beginner', ARRAY['Write Python programs','Understand data structures','Debug code','Build small applications'], ARRAY['Python','Programming Logic','Problem Solving','Debugging'], ARRAY['Technology'], ARRAY['Junior Developer','Software Developer'], 'English', 4.80, 489, true, true, 3200, true),
('00000000-0000-0000-0001-000000000004', 'Web Development with JavaScript & React', 'web-dev-javascript-react', 'Build modern, interactive web applications using JavaScript, HTML, CSS, and React.', 'Build modern web apps with React and JavaScript', 'WeThinkCode_', true, '5', 25, 89900, 'paid_once', 'blended', 'project', 80, 'intermediate', ARRAY['Build React applications','Consume REST APIs','Manage application state','Deploy web applications'], ARRAY['JavaScript','React','HTML','CSS','REST APIs','Git'], ARRAY['Technology'], ARRAY['Frontend Developer','Full Stack Developer'], 'English', 4.90, 367, true, true, 2750, true),
('00000000-0000-0000-0001-000000000005', 'Backend Development with Node.js', 'backend-nodejs', 'Build scalable server-side applications with Node.js, Express, and PostgreSQL.', 'Build production-grade backend services', 'WeThinkCode_', true, '6', 25, 99900, 'paid_once', 'blended', 'project', 80, 'intermediate', ARRAY['Design RESTful APIs','Build authentication systems','Work with databases','Deploy to cloud'], ARRAY['Node.js','Express','PostgreSQL','API Design','Authentication'], ARRAY['Technology'], ARRAY['Backend Developer','Full Stack Developer'], 'English', 4.70, 198, true, true, 1890, true),
('00000000-0000-0000-0001-000000000008', 'Data Analytics with Excel & SQL', 'data-analytics-excel-sql', 'Learn to analyse data using advanced Excel functions and SQL queries.', 'Analyse data with Excel and SQL', 'Explore Data Science Academy', true, '5', 20, 65000, 'paid_once', 'online', 'case_study', 50, 'beginner', ARRAY['Write complex SQL queries','Build Excel dashboards','Clean and transform data','Present data insights'], ARRAY['SQL','Excel','Data Analysis','Data Visualization'], ARRAY['Technology','Finance & Banking','General'], ARRAY['Data Analyst','Business Analyst'], 'English', 4.60, 278, true, true, 2340, true),
('00000000-0000-0000-0001-000000000009', 'Data Science with Python', 'data-science-python', 'Dive into data science using Python, Pandas, NumPy, and Matplotlib.', 'Master data science with Python tools', 'Explore Data Science Academy', true, '6', 25, 129900, 'paid_once', 'blended', 'project', 80, 'intermediate', ARRAY['Analyse datasets with Pandas','Perform statistical analysis','Create data visualizations','Build predictive models'], ARRAY['Python','Pandas','NumPy','Statistics','Data Visualization'], ARRAY['Technology','Finance & Banking'], ARRAY['Data Scientist','Data Analyst'], 'English', 4.80, 312, true, true, 2560, true),
('00000000-0000-0000-0001-000000000018', 'Professional Communication & Business Writing', 'professional-communication', 'Master business writing, presentation skills, email etiquette, and report writing.', 'Communicate like a pro in any workplace', 'CAPACITI', true, '4', 12, 0, 'free', 'online', 'video', 25, 'beginner', ARRAY['Write professional emails','Create business reports','Present confidently','Navigate cross-cultural communication'], ARRAY['Business Writing','Presentation Skills','Email Etiquette','Communication'], ARRAY['General'], ARRAY['Any'], 'English', 4.60, 389, true, true, 3400, true),
('00000000-0000-0000-0001-000000000020', 'Career Readiness & Job Search Skills', 'career-readiness', 'Prepare for the South African job market: CV writing, interview skills, LinkedIn optimisation.', 'Land your dream job in South Africa', 'CAPACITI', false, '4', 10, 0, 'free', 'online', 'video', 15, 'beginner', ARRAY['Write winning CVs','Ace interviews','Build a professional network','Navigate SA labour market'], ARRAY['CV Writing','Interview Skills','LinkedIn','Networking'], ARRAY['General'], ARRAY['Any Entry Level'], 'English', 4.70, 512, true, false, 5200, true),
('00000000-0000-0000-0001-000000000031', 'Software Development Capstone Project', 'software-dev-capstone', 'Apply your full-stack development skills in a real-world capstone project.', 'Build a real-world software product', 'WeThinkCode_', true, '6', 30, 0, 'employer_funded', 'blended', 'project', 120, 'advanced', ARRAY['Deliver a full-stack application','Work in Agile teams','Present to stakeholders','Deploy to production'], ARRAY['Full Stack','Team Collaboration','Project Delivery','Presentation'], ARRAY['Technology'], ARRAY['Full Stack Developer'], 'English', 4.90, 78, true, false, 520, true),
('00000000-0000-0000-0001-000000000025', 'AI & Prompt Engineering for Professionals', 'ai-prompt-engineering', 'Learn to leverage AI tools effectively in the workplace.', 'Harness AI tools for workplace productivity', 'Explore Data Science Academy', false, '5', 10, 35000, 'paid_once', 'online', 'workshop', 20, 'beginner', ARRAY['Write effective AI prompts','Use AI tools ethically','Automate workplace tasks','Evaluate AI outputs critically'], ARRAY['AI','Prompt Engineering','AI Ethics','Automation'], ARRAY['Technology','General'], ARRAY['Any'], 'English', 4.80, 423, true, false, 3800, true)
